#include <stdio.h>
#include <unistd.h>
#include <getopt.h>
#include <stdlib.h>
#include <assert.h>
#include <string.h>
#include <sys/time.h>
#include <cuda_runtime.h>

#include "common.h"

#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

static int num_devices = 0;
static int do_verify = 0;

extern "C" void lud_cuda(float *d_m, int matrix_dim);

static int initialize(int platform_id_inuse, int device_id_inuse) {
    (void)platform_id_inuse;

    if (cudaGetDeviceCount(&num_devices) != cudaSuccess) {
        printf("ERROR: clGetDeviceIDs failed\n");
        return -1;
    }
    printf("num_devices = %d\n", num_devices);

    if (device_id_inuse > num_devices) {
        printf("Invalid Device Number\n");
        return -1;
    }

    if (cudaSetDevice(device_id_inuse) != cudaSuccess) {
        printf("ERROR: clGetDeviceIDs failed\n");
        return -1;
    }

    printf("Create GPU context\n");
    return 0;
}

static int shutdown() {
    cudaDeviceReset();
    num_devices = 0;
    return 0;
}

static struct option long_options[] = {
    {"input", 1, NULL, 'i'},
    {"size", 1, NULL, 's'},
    {"verify", 0, NULL, 'v'},
    {"platform", 1, NULL, 'p'},
    {"device", 1, NULL, 'd'},
    {0, 0, 0, 0}
};

int main(int argc, char *argv[]) {
#ifdef TIMING
    struct timeval tv;
    struct timeval tv_total_start;
    struct timeval tv_init_end;
    struct timeval tv_mem_alloc_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
          d2h_time = 0, close_time = 0, total_time = 0;
#endif

    printf("WG size of kernel = %d X %d\n", BLOCK_SIZE, BLOCK_SIZE);
    int matrix_dim = 32;
    int opt, option_index = 0;
    func_ret_t ret;
    const char *input_file = NULL;
    float *m, *mm;
    stopwatch sw;
    int platform_id_inuse = 0;
    int device_id_inuse = 0;

    while ((opt = getopt_long(argc, argv, "::vs:i:p:d:", long_options, &option_index)) != -1) {
        switch (opt) {
            case 'i':
                input_file = optarg;
                break;
            case 'v':
                do_verify = 1;
                break;
            case 's':
                matrix_dim = atoi(optarg);
                printf("Generate input matrix internally, size =%d\n", matrix_dim);
                break;
            case 'p':
                platform_id_inuse = atoi(optarg);
                break;
            case 'd':
                device_id_inuse = atoi(optarg);
                break;
            case '?':
                fprintf(stderr, "invalid option\n");
                break;
            case ':':
                fprintf(stderr, "missing argument\n");
                break;
            default:
                fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n", argv[0]);
                exit(EXIT_FAILURE);
        }
    }

    if ((optind < argc) || (optind == 1)) {
        fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n", argv[0]);
        exit(EXIT_FAILURE);
    }

    if (input_file) {
        printf("Reading matrix from file %s\n", input_file);
        ret = create_matrix_from_file(&m, input_file, &matrix_dim);
        if (ret != RET_SUCCESS) {
            m = NULL;
            fprintf(stderr, "error create matrix from file %s\n", input_file);
            exit(EXIT_FAILURE);
        }
    } else if (matrix_dim) {
        printf("Creating matrix internally size=%d\n", matrix_dim);
        ret = create_matrix(&m, matrix_dim);
        if (ret != RET_SUCCESS) {
            m = NULL;
            fprintf(stderr, "error create matrix internally size=%d\n", matrix_dim);
            exit(EXIT_FAILURE);
        }
    } else {
        printf("No input file specified!\n");
        exit(EXIT_FAILURE);
    }

    if (do_verify) {
        printf("Before LUD\n");
        matrix_duplicate(m, &mm, matrix_dim);
    }

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif
    if (initialize(platform_id_inuse, device_id_inuse)) return -1;

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    float *d_m = NULL;
    if (cudaMalloc((void **)&d_m, (size_t)matrix_dim * (size_t)matrix_dim * sizeof(float)) != cudaSuccess) {
        printf("ERROR: clCreateBuffer d_m (size:%d) => %d\n", matrix_dim * matrix_dim, -1);
        return -1;
    }

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    stopwatch_start(&sw);

#ifdef TIMING
    cudaEvent_t ev1, ev2;
    cudaEventCreate(&ev1);
    cudaEventCreate(&ev2);
    cudaEventRecord(ev1, 0);
#endif
    if (cudaMemcpy(d_m, m, (size_t)matrix_dim * (size_t)matrix_dim * sizeof(float), cudaMemcpyHostToDevice) != cudaSuccess) {
        printf("ERROR: clEnqueueWriteBuffer d_m (size:%d) => %d\n", matrix_dim * matrix_dim, -1);
        return -1;
    }
#ifdef TIMING
    cudaEventRecord(ev2, 0);
    cudaEventSynchronize(ev2);
    {
        float ms = 0.0f;
        cudaEventElapsedTime(&ms, ev1, ev2);
        h2d_time += ms;
    }
#endif

#ifdef TIMING
    cudaEventRecord(ev1, 0);
#endif
    lud_cuda(d_m, matrix_dim);
    cudaDeviceSynchronize();
#ifdef TIMING
    cudaEventRecord(ev2, 0);
    cudaEventSynchronize(ev2);
    {
        float ms = 0.0f;
        cudaEventElapsedTime(&ms, ev1, ev2);
        kernel_time += ms;
    }
#endif

#ifdef TIMING
    cudaEventRecord(ev1, 0);
#endif
    if (cudaMemcpy(m, d_m, (size_t)matrix_dim * (size_t)matrix_dim * sizeof(float), cudaMemcpyDeviceToHost) != cudaSuccess) {
        printf("ERROR: clEnqueueReadBuffer  d_m (size:%d) => %d\n", matrix_dim * matrix_dim, -1);
        return -1;
    }
#ifdef TIMING
    cudaEventRecord(ev2, 0);
    cudaEventSynchronize(ev2);
    {
        float ms = 0.0f;
        cudaEventElapsedTime(&ms, ev1, ev2);
        d2h_time += ms;
    }
    cudaEventDestroy(ev1);
    cudaEventDestroy(ev2);
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif
    cudaFree(d_m);
#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    if (do_verify) {
        printf("After LUD\n");
        printf(">>>Verify<<<<\n");
        lud_verify(mm, m, matrix_dim);
        free(mm);
    }

    free(m);

    if (shutdown()) return -1;

    return 0;
}
